import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.lang.reflect.Method;

import org.apache.commons.csv.CSVParser;
import org.apache.commons.csv.Lexer;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.Mock;
import org.mockito.MockitoAnnotations;

class CSVParserTest {

    @Mock
    private Lexer lexerMock;

    private CSVParser csvParser;

    @BeforeEach
    void setUp() throws Exception {
        MockitoAnnotations.openMocks(this);
        // Create CSVParser instance with a dummy CSVFormat and Reader using reflection since no public constructor available here
        csvParser = (CSVParser) java.lang.reflect.Constructor.class
                .getDeclaredConstructor(CSVParser.class.getDeclaredConstructor(java.io.Reader.class, org.apache.commons.csv.CSVFormat.class).getParameterTypes())
                .newInstance(null);
        // Use reflection to set the private lexer field
        var lexerField = CSVParser.class.getDeclaredField("lexer");
        lexerField.setAccessible(true);
        lexerField.set(csvParser, lexerMock);
    }

    @Test
    void testGetFirstEndOfLine_ReturnsExpected() {
        String expectedEol = "\n";
        when(lexerMock.getFirstEol()).thenReturn(expectedEol);

        String actualEol = csvParser.getFirstEndOfLine();

        assertEquals(expectedEol, actualEol);
        verify(lexerMock).getFirstEol();
    }

    @Test
    void testGetFirstEndOfLine_ReturnsNull() {
        when(lexerMock.getFirstEol()).thenReturn(null);

        String actualEol = csvParser.getFirstEndOfLine();

        assertNull(actualEol);
        verify(lexerMock).getFirstEol();
    }
}
